head.script:
{
  "@context": "https://schema.org",
  "@type": "WebSite",
  "name": "DiskritProgram",
  "url": "",
  "description": "Platform repository program interaktif untuk membantu mahasiswa memahami dan menyelesaikan berbagai permasalahan Matematika Diskrit.",
  "potentialAction": {
    "@type": "SearchAction",
    "target": "search?q={search_term_string}",
    "query-input": "required name=search_term_string"
  }
}

head.b:skin:

/* ============================================================
   DISKRITPROGRAM — BLOGGER XML THEME
   Modern SaaS Dashboard | Educational Repository
   ============================================================ */

/* === CSS VARIABLES === */
:root {
  --dp-primary: #2563EB;
  --dp-primary-dark: #1D4ED8;
  --dp-primary-light: #3B82F6;
  --dp-primary-bg: #EFF6FF;
  --dp-secondary: #0F172A;
  --dp-bg: #F8FAFC;
  --dp-card: #FFFFFF;
  --dp-border: #E2E8F0;
  --dp-border-light: #F1F5F9;
  --dp-success: #10B981;
  --dp-warning: #F59E0B;
  --dp-danger: #EF4444;
  --dp-text-primary: #0F172A;
  --dp-text-secondary: #475569;
  --dp-text-muted: #94A3B8;
  --dp-text-inverse: #FFFFFF;
  --dp-sidebar-width: 280px;
  --dp-topbar-height: 80px;
  --dp-font-sans: 'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, sans-serif;
  --dp-font-mono: 'JetBrains Mono', 'Courier New', monospace;
  --dp-radius-sm: 6px;
  --dp-radius: 10px;
  --dp-radius-lg: 16px;
  --dp-radius-xl: 24px;
  --dp-shadow-sm: 0 1px 3px rgba(0,0,0,0.06), 0 1px 2px rgba(0,0,0,0.04);
  --dp-shadow: 0 4px 6px -1px rgba(0,0,0,0.08), 0 2px 4px -1px rgba(0,0,0,0.04);
  --dp-shadow-md: 0 10px 15px -3px rgba(0,0,0,0.08), 0 4px 6px -2px rgba(0,0,0,0.04);
  --dp-shadow-lg: 0 20px 25px -5px rgba(0,0,0,0.08), 0 10px 10px -5px rgba(0,0,0,0.03);
  --dp-transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  --dp-transition-slow: all 0.35s cubic-bezier(0.4, 0, 0.2, 1);
}

/* === DARK MODE === */
body.dp-dark {
  --dp-primary: #3B82F6;
  --dp-primary-dark: #2563EB;
  --dp-primary-light: #60A5FA;
  --dp-primary-bg: #1E3A5F;
  --dp-secondary: #F8FAFC;
  --dp-bg: #0F172A;
  --dp-card: #1E293B;
  --dp-border: #334155;
  --dp-border-light: #1E293B;
  --dp-text-primary: #F1F5F9;
  --dp-text-secondary: #94A3B8;
  --dp-text-muted: #64748B;
  --dp-shadow-sm: 0 1px 3px rgba(0,0,0,0.3);
  --dp-shadow: 0 4px 6px -1px rgba(0,0,0,0.4);
  --dp-shadow-md: 0 10px 15px -3px rgba(0,0,0,0.4);
  --dp-shadow-lg: 0 20px 25px -5px rgba(0,0,0,0.4);
}

/* === RESET & BASE === */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--dp-font-sans);
  background-color: var(--dp-bg);
  color: var(--dp-text-primary);
  line-height: 1.6;
  font-size: 15px;
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  transition: background-color 0.3s ease, color 0.3s ease;
}

a {
  color: var(--dp-primary);
  text-decoration: none;
  transition: var(--dp-transition);
}
a:hover { color: var(--dp-primary-dark); }

img { max-width: 100%; height: auto; display: block; }

/* === LAYOUT WRAPPER === */
.dp-layout {
  display: flex;
  min-height: 100vh;
}

/* === SIDEBAR === */
.dp-sidebar {
  position: fixed;
  top: 0;
  left: 0;
  width: var(--dp-sidebar-width);
  height: 100vh;
  background: var(--dp-card);
  border-right: 1px solid var(--dp-border);
  display: flex;
  flex-direction: column;
  z-index: 100;
  overflow-y: auto;
  overflow-x: hidden;
  transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1), background 0.3s ease;
}

.dp-sidebar::-webkit-scrollbar { width: 4px; }
.dp-sidebar::-webkit-scrollbar-track { background: transparent; }
.dp-sidebar::-webkit-scrollbar-thumb { background: var(--dp-border); border-radius: 2px; }

.dp-sidebar-logo {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 24px 20px 20px;
  border-bottom: 1px solid var(--dp-border-light);
  text-decoration: none;
}

.dp-sidebar-logo-icon {
  width: 40px;
  height: 40px;
  background: linear-gradient(135deg, var(--dp-primary), var(--dp-primary-dark));
  border-radius: var(--dp-radius);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 18px;
  font-weight: 800;
  color: white;
  flex-shrink: 0;
  box-shadow: 0 4px 12px rgba(37, 99, 235, 0.3);
}

.dp-sidebar-logo-text { flex: 1; }

.dp-sidebar-logo-name {
  font-size: 15px;
  font-weight: 700;
  color: var(--dp-text-primary);
  letter-spacing: -0.3px;
  line-height: 1.2;
}

.dp-sidebar-logo-sub {
  font-size: 11px;
  color: var(--dp-text-muted);
  line-height: 1.3;
  margin-top: 2px;
}

.dp-sidebar-nav {
  flex: 1;
  padding: 16px 12px;
  overflow-y: auto;
}

.dp-nav-section {
  margin-bottom: 20px;
}

.dp-nav-section-title {
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: var(--dp-text-muted);
  padding: 0 8px;
  margin-bottom: 6px;
}

.dp-nav-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 9px 10px;
  border-radius: var(--dp-radius-sm);
  color: var(--dp-text-secondary);
  font-size: 13.5px;
  font-weight: 500;
  text-decoration: none;
  transition: var(--dp-transition);
  cursor: pointer;
  position: relative;
}

.dp-nav-item:hover {
  background: var(--dp-primary-bg);
  color: var(--dp-primary);
}

.dp-nav-item.active {
  background: var(--dp-primary-bg);
  color: var(--dp-primary);
  font-weight: 600;
}

.dp-nav-item.active::before {
  content: '';
  position: absolute;
  left: -12px;
  top: 50%;
  transform: translateY(-50%);
  width: 3px;
  height: 20px;
  background: var(--dp-primary);
  border-radius: 0 3px 3px 0;
}

.dp-nav-icon {
  width: 20px;
  height: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  flex-shrink: 0;
}

.dp-nav-badge {
  margin-left: auto;
  background: var(--dp-primary-bg);
  color: var(--dp-primary);
  font-size: 10px;
  font-weight: 600;
  padding: 2px 7px;
  border-radius: 10px;
  min-width: 20px;
  text-align: center;
}

.dp-nav-item.active .dp-nav-badge {
  background: var(--dp-primary);
  color: white;
}

.dp-sidebar-footer {
  padding: 12px;
  border-top: 1px solid var(--dp-border-light);
}

/* === MAIN CONTENT === */
.dp-main {
  margin-left: var(--dp-sidebar-width);
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
}

/* === TOPBAR === */
.dp-topbar {
  position: sticky;
  top: 0;
  z-index: 50;
  height: var(--dp-topbar-height);
  background: var(--dp-card);
  border-bottom: 1px solid var(--dp-border);
  display: flex;
  align-items: center;
  padding: 0 28px;
  gap: 16px;
  transition: background 0.3s ease, border-color 0.3s ease;
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}

.dp-topbar-left {
  display: flex;
  align-items: center;
  gap: 16px;
  flex: 1;
}

.dp-mobile-menu-btn {
  display: none;
  width: 36px;
  height: 36px;
  border: 1px solid var(--dp-border);
  border-radius: var(--dp-radius-sm);
  background: transparent;
  cursor: pointer;
  align-items: center;
  justify-content: center;
  color: var(--dp-text-secondary);
  transition: var(--dp-transition);
}

.dp-mobile-menu-btn:hover {
  background: var(--dp-bg);
  color: var(--dp-text-primary);
}

/* === SEARCH === */
.dp-search-wrapper {
  position: relative;
  flex: 1;
  max-width: 480px;
}

.dp-search-icon {
  position: absolute;
  left: 14px;
  top: 50%;
  transform: translateY(-50%);
  color: var(--dp-text-muted);
  pointer-events: none;
}

.dp-search-input {
  width: 100%;
  height: 40px;
  padding: 0 14px 0 42px;
  background: var(--dp-bg);
  border: 1px solid var(--dp-border);
  border-radius: var(--dp-radius);
  font-family: var(--dp-font-sans);
  font-size: 13.5px;
  color: var(--dp-text-primary);
  outline: none;
  transition: var(--dp-transition);
}

.dp-search-input::placeholder { color: var(--dp-text-muted); }

.dp-search-input:focus {
  border-color: var(--dp-primary);
  background: var(--dp-card);
  box-shadow: 0 0 0 3px rgba(37, 99, 235, 0.1);
}

.dp-search-results {
  position: absolute;
  top: calc(100% + 6px);
  left: 0;
  right: 0;
  background: var(--dp-card);
  border: 1px solid var(--dp-border);
  border-radius: var(--dp-radius);
  box-shadow: var(--dp-shadow-lg);
  max-height: 360px;
  overflow-y: auto;
  z-index: 200;
  display: none;
}

.dp-search-results.active { display: block; }

.dp-search-result-item {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 12px 16px;
  cursor: pointer;
  transition: var(--dp-transition);
  border-bottom: 1px solid var(--dp-border-light);
  text-decoration: none;
  color: var(--dp-text-primary);
}

.dp-search-result-item:last-child { border-bottom: none; }
.dp-search-result-item:hover { background: var(--dp-bg); }

.dp-search-result-icon {
  width: 32px;
  height: 32px;
  background: var(--dp-primary-bg);
  border-radius: var(--dp-radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  flex-shrink: 0;
}

.dp-search-result-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--dp-text-primary);
  line-height: 1.3;
}

.dp-search-result-meta {
  font-size: 11px;
  color: var(--dp-text-muted);
  margin-top: 2px;
}

.dp-search-empty {
  padding: 20px 16px;
  text-align: center;
  color: var(--dp-text-muted);
  font-size: 13px;
}

/* === TOPBAR RIGHT === */
.dp-topbar-right {
  display: flex;
  align-items: center;
  gap: 8px;
}

.dp-topbar-btn {
  width: 36px;
  height: 36px;
  border: 1px solid var(--dp-border);
  border-radius: var(--dp-radius-sm);
  background: transparent;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--dp-text-secondary);
  transition: var(--dp-transition);
  font-size: 16px;
}

.dp-topbar-btn:hover {
  background: var(--dp-bg);
  color: var(--dp-text-primary);
  border-color: var(--dp-primary);
}

/* === PAGE CONTENT === */
.dp-page-content {
  flex: 1;
  padding: 0;
  overflow: hidden;
}

/* === HERO SECTION === */
.dp-hero {
  background: linear-gradient(135deg, #001B5E 0%, #0A2A7A 30%, #1B40A8 65%, #2563EB 100%);
  padding: 60px 40px;
  position: relative;
  overflow: hidden;
}

.dp-hero::before {
  content: '';
  position: absolute;
  inset: 0;
  background:
    radial-gradient(ellipse at 70% 50%, rgba(37, 99, 235, 0.4) 0%, transparent 60%),
    radial-gradient(ellipse at 20% 20%, rgba(59, 130, 246, 0.2) 0%, transparent 50%);
  pointer-events: none;
}

.dp-hero::after {
  content: '';
  position: absolute;
  top: -50%;
  right: -10%;
  width: 500px;
  height: 500px;
  background: radial-gradient(circle, rgba(255,255,255,0.04) 0%, transparent 70%);
  pointer-events: none;
}

.dp-hero-grid {
  display: grid;
  grid-template-columns: 1fr auto;
  gap: 40px;
  align-items: center;
  max-width: 1200px;
  position: relative;
  z-index: 1;
}

.dp-hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: rgba(255,255,255,0.12);
  border: 1px solid rgba(255,255,255,0.2);
  color: rgba(255,255,255,0.9);
  font-size: 11px;
  font-weight: 600;
  padding: 4px 12px;
  border-radius: 20px;
  letter-spacing: 0.5px;
  text-transform: uppercase;
  margin-bottom: 16px;
  backdrop-filter: blur(4px);
}

.dp-hero-title {
  font-size: clamp(26px, 3.5vw, 40px);
  font-weight: 800;
  color: white;
  line-height: 1.15;
  letter-spacing: -0.5px;
  margin-bottom: 16px;
}

.dp-hero-title span {
  background: linear-gradient(135deg, #60A5FA, #93C5FD);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.dp-hero-desc {
  font-size: 15px;
  color: rgba(255,255,255,0.75);
  line-height: 1.7;
  max-width: 520px;
  margin-bottom: 28px;
}

.dp-hero-actions {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
}

.dp-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 22px;
  border-radius: var(--dp-radius);
  font-family: var(--dp-font-sans);
  font-size: 13.5px;
  font-weight: 600;
  cursor: pointer;
  transition: var(--dp-transition);
  border: none;
  text-decoration: none;
  white-space: nowrap;
}

.dp-btn-primary {
  background: white;
  color: var(--dp-primary-dark);
  box-shadow: 0 4px 14px rgba(0,0,0,0.15);
}

.dp-btn-primary:hover {
  background: #F0F4FF;
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(0,0,0,0.2);
  color: var(--dp-primary-dark);
}

.dp-btn-outline {
  background: rgba(255,255,255,0.1);
  color: white;
  border: 1px solid rgba(255,255,255,0.3);
  backdrop-filter: blur(4px);
}

.dp-btn-outline:hover {
  background: rgba(255,255,255,0.18);
  border-color: rgba(255,255,255,0.5);
  color: white;
  transform: translateY(-1px);
}

.dp-hero-code-card {
  background: rgba(15, 23, 42, 0.85);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: var(--dp-radius-lg);
  padding: 20px;
  backdrop-filter: blur(8px);
  min-width: 300px;
  max-width: 360px;
}

.dp-hero-code-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 14px;
}

.dp-code-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
}
.dp-code-dot.red { background: #FF5F57; }
.dp-code-dot.yellow { background: #FEBC2E; }
.dp-code-dot.green { background: #28C840; }

.dp-hero-code-title {
  margin-left: 8px;
  font-size: 11px;
  color: rgba(255,255,255,0.4);
  font-family: var(--dp-font-mono);
}

.dp-hero-code pre {
  font-family: var(--dp-font-mono);
  font-size: 12px;
  line-height: 1.7;
  color: #E2E8F0;
  white-space: pre;
  overflow-x: auto;
}

.dp-code-kw { color: #C084FC; }
.dp-code-fn { color: #60A5FA; }
.dp-code-str { color: #86EFAC; }
.dp-code-num { color: #FCA5A5; }
.dp-code-cm { color: #64748B; }

/* === STATS BAR === */
.dp-stats-bar {
  background: var(--dp-card);
  border-bottom: 1px solid var(--dp-border);
  padding: 18px 40px;
  display: flex;
  gap: 0;
}

.dp-stat-item {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 0 20px;
  border-right: 1px solid var(--dp-border);
}

.dp-stat-item:first-child { padding-left: 0; }
.dp-stat-item:last-child { border-right: none; }

.dp-stat-icon {
  width: 40px;
  height: 40px;
  border-radius: var(--dp-radius);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 18px;
  flex-shrink: 0;
}

.dp-stat-icon.blue { background: #EFF6FF; }
.dp-stat-icon.green { background: #ECFDF5; }
.dp-stat-icon.orange { background: #FFFBEB; }
.dp-stat-icon.purple { background: #F5F3FF; }

body.dp-dark .dp-stat-icon.blue { background: rgba(37,99,235,0.15); }
body.dp-dark .dp-stat-icon.green { background: rgba(16,185,129,0.15); }
body.dp-dark .dp-stat-icon.orange { background: rgba(245,158,11,0.15); }
body.dp-dark .dp-stat-icon.purple { background: rgba(139,92,246,0.15); }

.dp-stat-value {
  font-size: 22px;
  font-weight: 800;
  color: var(--dp-text-primary);
  line-height: 1;
  letter-spacing: -0.5px;
}

.dp-stat-label {
  font-size: 12px;
  color: var(--dp-text-muted);
  margin-top: 2px;
}

/* === SECTION HEADER === */
.dp-section-header {
  padding: 36px 40px 20px;
}

.dp-section-title {
  font-size: 20px;
  font-weight: 700;
  color: var(--dp-text-primary);
  letter-spacing: -0.3px;
  margin-bottom: 4px;
}

.dp-section-sub {
  font-size: 13.5px;
  color: var(--dp-text-secondary);
}

/* === CATEGORY GRID === */
.dp-category-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
  padding: 0 40px 36px;
}

.dp-cat-card {
  background: var(--dp-card);
  border: 1px solid var(--dp-border);
  border-radius: var(--dp-radius-lg);
  padding: 20px;
  text-decoration: none;
  display: flex;
  flex-direction: column;
  gap: 12px;
  transition: var(--dp-transition-slow);
  position: relative;
  overflow: hidden;
}

.dp-cat-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: var(--cat-color, var(--dp-primary));
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.3s ease;
  border-radius: 0 0 3px 3px;
}

.dp-cat-card:hover {
  border-color: var(--cat-color, var(--dp-primary));
  transform: translateY(-3px);
  box-shadow: var(--dp-shadow-md);
}

.dp-cat-card:hover::before { transform: scaleX(1); }

.dp-cat-icon {
  width: 46px;
  height: 46px;
  border-radius: var(--dp-radius);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 22px;
  background: var(--cat-bg, var(--dp-primary-bg));
  flex-shrink: 0;
}

.dp-cat-name {
  font-size: 14px;
  font-weight: 700;
  color: var(--dp-text-primary);
  margin-bottom: 4px;
  letter-spacing: -0.2px;
}

.dp-cat-desc {
  font-size: 12px;
  color: var(--dp-text-secondary);
  line-height: 1.5;
  flex: 1;
}

.dp-cat-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: 10px;
  border-top: 1px solid var(--dp-border-light);
}

.dp-cat-count {
  font-size: 11px;
  color: var(--dp-text-muted);
  font-weight: 500;
}

.dp-cat-link {
  font-size: 12px;
  font-weight: 600;
  color: var(--cat-color, var(--dp-primary));
  display: flex;
  align-items: center;
  gap: 4px;
}

/* === POST LIST === */
.dp-posts-section {
  padding: 0 40px 40px;
}

.dp-post-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
}

.dp-post-card {
  background: var(--dp-card);
  border: 1px solid var(--dp-border);
  border-radius: var(--dp-radius-lg);
  overflow: hidden;
  transition: var(--dp-transition-slow);
  text-decoration: none;
  display: flex;
  flex-direction: column;
}

.dp-post-card:hover {
  transform: translateY(-3px);
  box-shadow: var(--dp-shadow-md);
  border-color: var(--dp-primary);
}

.dp-post-card-header {
  padding: 18px 18px 0;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
}

.dp-post-label {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  padding: 3px 9px;
  border-radius: 20px;
  background: var(--dp-primary-bg);
  color: var(--dp-primary);
}

.dp-post-card-body {
  padding: 12px 18px 16px;
  flex: 1;
}

.dp-post-title {
  font-size: 14px;
  font-weight: 700;
  color: var(--dp-text-primary);
  line-height: 1.4;
  margin-bottom: 6px;
  letter-spacing: -0.2px;
}

.dp-post-snippet {
  font-size: 12px;
  color: var(--dp-text-secondary);
  line-height: 1.6;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.dp-post-card-footer {
  padding: 12px 18px;
  border-top: 1px solid var(--dp-border-light);
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.dp-post-date {
  font-size: 11px;
  color: var(--dp-text-muted);
  display: flex;
  align-items: center;
  gap: 4px;
}

.dp-post-arrow {
  font-size: 13px;
  color: var(--dp-primary);
  transition: transform 0.2s ease;
}

.dp-post-card:hover .dp-post-arrow { transform: translateX(4px); }

/* === SINGLE POST / PROGRAM === */
.dp-post-page {
  max-width: 900px;
  margin: 0 auto;
  padding: 36px 40px;
}

.dp-breadcrumb {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
  color: var(--dp-text-muted);
  margin-bottom: 20px;
  flex-wrap: wrap;
}

.dp-breadcrumb a {
  color: var(--dp-text-muted);
  transition: var(--dp-transition);
}
.dp-breadcrumb a:hover { color: var(--dp-primary); }
.dp-breadcrumb-sep { color: var(--dp-border); }
.dp-breadcrumb-current { color: var(--dp-text-secondary); font-weight: 500; }

.dp-post-header {
  margin-bottom: 28px;
}

.dp-post-labels {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  margin-bottom: 14px;
}

.dp-post-label-tag {
  display: inline-flex;
  align-items: center;
  font-size: 11px;
  font-weight: 600;
  padding: 3px 10px;
  border-radius: 20px;
  background: var(--dp-primary-bg);
  color: var(--dp-primary);
  text-decoration: none;
  transition: var(--dp-transition);
}

.dp-post-label-tag:hover {
  background: var(--dp-primary);
  color: white;
}

.dp-post-main-title {
  font-size: clamp(22px, 3vw, 30px);
  font-weight: 800;
  color: var(--dp-text-primary);
  letter-spacing: -0.5px;
  line-height: 1.25;
  margin-bottom: 10px;
}

.dp-post-meta {
  display: flex;
  align-items: center;
  gap: 16px;
  font-size: 12px;
  color: var(--dp-text-muted);
  flex-wrap: wrap;
}

.dp-post-meta-item {
  display: flex;
  align-items: center;
  gap: 4px;
}

.dp-post-content {
  background: var(--dp-card);
  border: 1px solid var(--dp-border);
  border-radius: var(--dp-radius-lg);
  overflow: hidden;
}

.dp-post-content-inner {
  padding: 32px;
}

.dp-post-content-inner h2 {
  font-size: 18px;
  font-weight: 700;
  color: var(--dp-text-primary);
  margin: 28px 0 12px;
  padding-bottom: 8px;
  border-bottom: 2px solid var(--dp-border);
  letter-spacing: -0.3px;
}

.dp-post-content-inner h2:first-child { margin-top: 0; }

.dp-post-content-inner h3 {
  font-size: 15px;
  font-weight: 700;
  color: var(--dp-text-primary);
  margin: 20px 0 8px;
}

.dp-post-content-inner p {
  font-size: 14px;
  color: var(--dp-text-secondary);
  line-height: 1.75;
  margin-bottom: 14px;
}

.dp-post-content-inner ul, .dp-post-content-inner ol {
  padding-left: 20px;
  margin-bottom: 14px;
}

.dp-post-content-inner li {
  font-size: 14px;
  color: var(--dp-text-secondary);
  line-height: 1.75;
  margin-bottom: 4px;
}

.dp-post-content-inner pre {
  background: var(--dp-secondary);
  color: #E2E8F0;
  border-radius: var(--dp-radius);
  padding: 18px;
  overflow-x: auto;
  font-family: var(--dp-font-mono);
  font-size: 13px;
  line-height: 1.6;
  margin: 14px 0;
}

body.dp-dark .dp-post-content-inner pre {
  background: #0F172A;
  border: 1px solid var(--dp-border);
}

.dp-post-content-inner code {
  font-family: var(--dp-font-mono);
  font-size: 12.5px;
  background: var(--dp-bg);
  border: 1px solid var(--dp-border);
  padding: 1px 6px;
  border-radius: 4px;
  color: var(--dp-primary);
}

.dp-post-content-inner pre code {
  background: none;
  border: none;
  padding: 0;
  color: inherit;
}

/* === SOLVER CONTAINER === */
.dp-solver-wrapper {
  margin: 20px 0;
  border: 2px solid var(--dp-primary);
  border-radius: var(--dp-radius-lg);
  overflow: hidden;
  background: var(--dp-card);
}

.dp-solver-header {
  background: linear-gradient(135deg, var(--dp-primary), var(--dp-primary-dark));
  padding: 12px 20px;
  display: flex;
  align-items: center;
  gap: 10px;
}

.dp-solver-header-icon {
  font-size: 18px;
}

.dp-solver-header-title {
  font-size: 13px;
  font-weight: 700;
  color: white;
  flex: 1;
}

.dp-solver-header-badge {
  background: rgba(255,255,255,0.2);
  color: white;
  font-size: 10px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: 10px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.solver-container {
  padding: 20px;
  background: var(--dp-card);
}

/* Isolation for student solver styles */
.solver-container * {
  box-sizing: border-box;
}

/* === LABEL SEARCH PAGE === */
.dp-label-page {
  padding: 36px 40px;
}

.dp-label-header {
  margin-bottom: 28px;
  padding-bottom: 20px;
  border-bottom: 1px solid var(--dp-border);
}

.dp-label-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: var(--dp-primary-bg);
  color: var(--dp-primary);
  font-size: 12px;
  font-weight: 600;
  padding: 4px 12px;
  border-radius: 20px;
  margin-bottom: 10px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.dp-label-title {
  font-size: 24px;
  font-weight: 800;
  color: var(--dp-text-primary);
  letter-spacing: -0.5px;
  margin-bottom: 6px;
}

.dp-label-desc {
  font-size: 14px;
  color: var(--dp-text-secondary);
}

/* === ABOUT PAGE === */
.dp-about-page {
  padding: 36px 40px;
  max-width: 900px;
}

.dp-about-hero {
  background: linear-gradient(135deg, var(--dp-primary), var(--dp-primary-dark));
  border-radius: var(--dp-radius-xl);
  padding: 48px;
  color: white;
  margin-bottom: 32px;
  position: relative;
  overflow: hidden;
}

.dp-about-hero::before {
  content: '';
  position: absolute;
  top: -30%;
  right: -10%;
  width: 300px;
  height: 300px;
  background: radial-gradient(circle, rgba(255,255,255,0.1) 0%, transparent 70%);
}

.dp-about-title {
  font-size: 28px;
  font-weight: 800;
  margin-bottom: 12px;
  letter-spacing: -0.5px;
  position: relative;
  z-index: 1;
}

.dp-about-subtitle {
  font-size: 15px;
  opacity: 0.8;
  line-height: 1.7;
  max-width: 500px;
  position: relative;
  z-index: 1;
}

.dp-info-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
  margin-bottom: 28px;
}

.dp-info-card {
  background: var(--dp-card);
  border: 1px solid var(--dp-border);
  border-radius: var(--dp-radius-lg);
  padding: 20px;
  text-align: center;
}

.dp-info-card-icon {
  font-size: 32px;
  margin-bottom: 10px;
}

.dp-info-card-title {
  font-size: 14px;
  font-weight: 700;
  color: var(--dp-text-primary);
  margin-bottom: 6px;
}

.dp-info-card-text {
  font-size: 12.5px;
  color: var(--dp-text-secondary);
  line-height: 1.6;
}

/* === PAGINATION === */
.dp-pagination {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 28px 40px;
}

.dp-page-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 16px;
  border: 1px solid var(--dp-border);
  border-radius: var(--dp-radius);
  background: var(--dp-card);
  color: var(--dp-text-secondary);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  transition: var(--dp-transition);
  text-decoration: none;
  font-family: var(--dp-font-sans);
}

.dp-page-btn:hover {
  border-color: var(--dp-primary);
  color: var(--dp-primary);
  background: var(--dp-primary-bg);
}

/* === FOOTER === */
.dp-footer {
  background: var(--dp-card);
  border-top: 1px solid var(--dp-border);
  padding: 20px 40px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 12px;
}

.dp-footer-left {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 13px;
  color: var(--dp-text-muted);
}

.dp-footer-logo {
  font-size: 14px;
  font-weight: 700;
  color: var(--dp-primary);
}

.dp-footer-links {
  display: flex;
  gap: 16px;
}

.dp-footer-links a {
  font-size: 12px;
  color: var(--dp-text-muted);
  text-decoration: none;
  transition: var(--dp-transition);
}

.dp-footer-links a:hover { color: var(--dp-primary); }

/* === SIDEBAR OVERLAY (mobile) === */
.dp-sidebar-overlay {
  display: none;
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.5);
  z-index: 90;
  backdrop-filter: blur(2px);
}

.dp-sidebar-overlay.active { display: block; }

/* === SCROLL TO TOP === */
.dp-scroll-top {
  position: fixed;
  bottom: 24px;
  right: 24px;
  width: 40px;
  height: 40px;
  background: var(--dp-primary);
  color: white;
  border: none;
  border-radius: var(--dp-radius);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 16px;
  box-shadow: var(--dp-shadow-md);
  transition: var(--dp-transition);
  opacity: 0;
  transform: translateY(10px);
  pointer-events: none;
  z-index: 80;
}

.dp-scroll-top.visible {
  opacity: 1;
  transform: translateY(0);
  pointer-events: all;
}

.dp-scroll-top:hover {
  background: var(--dp-primary-dark);
  transform: translateY(-2px);
  box-shadow: var(--dp-shadow-lg);
}

/* === UTILITY === */
.dp-divider {
  height: 1px;
  background: var(--dp-border);
  margin: 0 40px;
}

.dp-empty-state {
  text-align: center;
  padding: 60px 20px;
  color: var(--dp-text-muted);
}

.dp-empty-state-icon { font-size: 48px; margin-bottom: 14px; }
.dp-empty-state-title { font-size: 17px; font-weight: 700; color: var(--dp-text-secondary); margin-bottom: 6px; }
.dp-empty-state-text { font-size: 13.5px; line-height: 1.6; }

/* === INFO BOX === */
.dp-info-box {
  display: flex;
  gap: 14px;
  background: var(--dp-primary-bg);
  border: 1px solid rgba(37,99,235,0.2);
  border-radius: var(--dp-radius);
  padding: 16px;
  margin: 0 40px 28px;
}

.dp-info-box-icon {
  font-size: 20px;
  flex-shrink: 0;
}

.dp-info-box-content {}
.dp-info-box-title {
  font-size: 13px;
  font-weight: 700;
  color: var(--dp-primary);
  margin-bottom: 4px;
}

.dp-info-box-text {
  font-size: 12.5px;
  color: var(--dp-text-secondary);
  line-height: 1.5;
}

.dp-info-box-link {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  font-size: 12px;
  font-weight: 600;
  color: var(--dp-primary);
  background: var(--dp-card);
  border: 1px solid var(--dp-border);
  border-radius: var(--dp-radius-sm);
  padding: 6px 14px;
  margin-left: auto;
  white-space: nowrap;
  text-decoration: none;
  transition: var(--dp-transition);
  align-self: center;
}

.dp-info-box-link:hover {
  background: var(--dp-primary);
  color: white;
  border-color: var(--dp-primary);
}

/* === LOADING === */
.dp-loading {
  display: inline-block;
  width: 16px;
  height: 16px;
  border: 2px solid var(--dp-border);
  border-top-color: var(--dp-primary);
  border-radius: 50%;
  animation: dp-spin 0.6s linear infinite;
}

@keyframes dp-spin {
  to { transform: rotate(360deg); }
}

/* === ANIMATIONS === */
@keyframes dp-fade-in {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

.dp-animate-in {
  animation: dp-fade-in 0.4s ease both;
}

.dp-animate-delay-1 { animation-delay: 0.1s; }
.dp-animate-delay-2 { animation-delay: 0.2s; }
.dp-animate-delay-3 { animation-delay: 0.3s; }
.dp-animate-delay-4 { animation-delay: 0.4s; }

/* === RESPONSIVE === */
@media (max-width: 1200px) {
  .dp-category-grid { grid-template-columns: repeat(3, 1fr); }
  .dp-post-grid { grid-template-columns: repeat(2, 1fr); }
}

@media (max-width: 1024px) {
  .dp-hero { padding: 40px 28px; }
  .dp-hero-grid { grid-template-columns: 1fr; }
  .dp-hero-code-card { display: none; }
  .dp-section-header, .dp-posts-section, .dp-label-page, .dp-about-page { padding-left: 28px; padding-right: 28px; }
  .dp-category-grid { padding: 0 28px 28px; }
  .dp-stats-bar { padding: 14px 28px; flex-wrap: wrap; gap: 10px; }
  .dp-stat-item { min-width: 150px; border-right: none; padding: 8px 10px; }
  .dp-footer, .dp-info-box, .dp-divider { margin-left: 0; margin-right: 0; padding-left: 28px; padding-right: 28px; }
}

@media (max-width: 900px) {
  :root { --dp-sidebar-width: 0px; }
  .dp-sidebar {
    width: 280px;
    transform: translateX(-100%);
  }
  .dp-sidebar.open { transform: translateX(0); }
  .dp-main { margin-left: 0; }
  .dp-mobile-menu-btn { display: flex; }
  .dp-category-grid { grid-template-columns: repeat(2, 1fr); }
  .dp-info-grid { grid-template-columns: repeat(2, 1fr); }
}

@media (max-width: 640px) {
  .dp-hero { padding: 28px 16px; }
  .dp-section-header, .dp-posts-section, .dp-label-page, .dp-about-page, .dp-post-page { padding: 20px 16px; }
  .dp-category-grid { grid-template-columns: 1fr; padding: 0 16px 20px; }
  .dp-post-grid { grid-template-columns: 1fr; }
  .dp-stats-bar { padding: 12px 16px; }
  .dp-topbar { padding: 0 16px; }
  .dp-hero-actions { flex-direction: column; }
  .dp-btn { width: 100%; justify-content: center; }
  .dp-footer { padding: 16px; flex-direction: column; text-align: center; }
  .dp-info-grid { grid-template-columns: 1fr; }
  .dp-pagination { padding: 20px 16px; }
  .dp-about-hero { padding: 28px; }
  .dp-info-box { flex-direction: column; margin: 0 16px 20px; }
  .dp-info-box-link { width: 100%; justify-content: center; }
  .dp-post-content-inner { padding: 20px; }
}

/* === PRINT === */
@media print {
  .dp-sidebar, .dp-topbar, .dp-footer, .dp-scroll-top { display: none !important; }
  .dp-main { margin-left: 0 !important; }
  .dp-post-page { padding: 20px !important; }
}

