def irisan(A, B):
    return A & B

A = {1, 2, 3, 4}
B = {3, 4, 5, 6}
print(gabungan(A,B))
# {1,2,3,4,5,6}

body.script:
//

/* ============================================================
   DISKRITPROGRAM — MAIN JAVASCRIPT
   ============================================================ */

(function() {
  'use strict';

  /* ============================
     DARK MODE
     ============================ */
  var DARK_KEY = 'dp_dark_mode';

  var SVG_MOON = '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M13.5 10a6 6 0 01-8-8 6 6 0 108 8z" stroke="currentColor" stroke-width="1.4" stroke-linecap="round" stroke-linejoin="round"/></svg>';
  var SVG_SUN = '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><circle cx="8" cy="8" r="3" stroke="currentColor" stroke-width="1.4"/><path d="M8 1v2M8 13v2M1 8h2M13 8h2M3.3 3.3l1.4 1.4M11.3 11.3l1.4 1.4M3.3 12.7l1.4-1.4M11.3 4.7l1.4-1.4" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/></svg>';

  function dpApplyDark(isDark) {
    if (isDark) {
      document.body.classList.add('dp-dark');
      var icon = document.getElementById('dpDarkIcon');
      if (icon) icon.innerHTML = SVG_SUN;
      localStorage.setItem(DARK_KEY, '1');
    } else {
      document.body.classList.remove('dp-dark');
      var icon = document.getElementById('dpDarkIcon');
      if (icon) icon.innerHTML = SVG_MOON;
      localStorage.setItem(DARK_KEY, '0');
    }
  }

  window.dpToggleDark = function() {
    var isDark = document.body.classList.contains('dp-dark');
    dpApplyDark(!isDark);
  };

  // Init dark mode from localStorage
  (function() {
    var saved = localStorage.getItem(DARK_KEY);
    if (saved === '1') {
      dpApplyDark(true);
    } else if (saved === null) {
      // Check system preference
      if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
        dpApplyDark(true);
      }
    }
  })();

  /* ============================
     MOBILE SIDEBAR
     ============================ */
  window.dpToggleSidebar = function(open) {
    var sidebar = document.getElementById('dpSidebar');
    var overlay = document.getElementById('dpSidebarOverlay');
    if (!sidebar || !overlay) return;
    if (open) {
      sidebar.classList.add('open');
      overlay.classList.add('active');
      document.body.style.overflow = 'hidden';
    } else {
      sidebar.classList.remove('open');
      overlay.classList.remove('active');
      document.body.style.overflow = '';
    }
  };

  /* ============================
     ACTIVE NAV ITEM
     ============================ */
  (function() {
    var path = window.location.href;
    var navItems = document.querySelectorAll('.dp-nav-item');
    navItems.forEach(function(item) {
      var href = item.getAttribute('href');
      if (href && path.indexOf(href.replace(window.location.origin, '')) !== -1 && href !== '/') {
        item.classList.add('active');
      }
    });
  })();

  /* ============================
     SCROLL TO TOP
     ============================ */
  (function() {
    var btn = document.getElementById('dpScrollTop');
    if (!btn) return;
    window.addEventListener('scroll', function() {
      if (window.scrollY > 400) {
        btn.classList.add('visible');
      } else {
        btn.classList.remove('visible');
      }
    }, { passive: true });
  })();

  /* ============================
     LIVE SEARCH
     ============================ */
  var searchIndex = [];
  var searchLoaded = false;
  var searchTimer = null;

  // Category data for search
  var categories = [
    { name: 'Himpunan yang Sama', label: 'Himpunan', icon: '<svg width="14" height="14" viewBox="0 0 14 14" fill="none"><circle cx="5" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/><circle cx="9" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/></svg>' },
    { name: 'Gabungan Himpunan', label: 'Himpunan', icon: '<svg width="14" height="14" viewBox="0 0 14 14" fill="none"><circle cx="5" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/><circle cx="9" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/></svg>' },
    { name: 'Subset', label: 'Himpunan', icon: '<svg width="14" height="14" viewBox="0 0 14 14" fill="none"><circle cx="5" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/><circle cx="9" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/></svg>' },
    { name: 'Komplemen', label: 'Himpunan', icon: '<svg width="14" height="14" viewBox="0 0 14 14" fill="none"><circle cx="5" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/><circle cx="9" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/></svg>' },
    { name: 'Himpunan Kuasa', label: 'Himpunan', icon: '<svg width="14" height="14" viewBox="0 0 14 14" fill="none"><circle cx="5" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/><circle cx="9" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/></svg>' },
    { name: 'Multiset', label: 'Himpunan', icon: '<svg width="14" height="14" viewBox="0 0 14 14" fill="none"><circle cx="5" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/><circle cx="9" cy="7" r="3.5" stroke="currentColor" stroke-width="1.4"/></svg>' },
