  var blogUrl = '';
  try {
    blogUrl = document.querySelector('a.dp-sidebar-logo') ?
      document.querySelector('a.dp-sidebar-logo').getAttribute('href') : '/';
  } catch(e) { blogUrl = '/'; }

  window.dpLiveSearch = function(query) {
    clearTimeout(searchTimer);
    var results = document.getElementById('dpSearchResults');
    if (!results) return;

    if (!query || query.trim().length < 2) {
      results.innerHTML = '';
      results.classList.remove('active');
      return;
    }

    searchTimer = setTimeout(function() {
      var q = query.toLowerCase().trim();
      var matched = categories.filter(function(item) {
        return item.name.toLowerCase().indexOf(q) !== -1 ||
               item.label.toLowerCase().replace('-', ' ').indexOf(q) !== -1;
      });

      if (matched.length === 0) {
        results.innerHTML = '<div class="dp-search-empty">Tidak ditemukan program untuk "<strong>' + query + '</strong>"</div>';
      } else {
        var html = '';
        matched.slice(0, 6).forEach(function(item) {
          var searchUrl = blogUrl + 'search/label/' + encodeURIComponent(item.label) + '?q=' + encodeURIComponent(item.name);
          html += '<a href="' + searchUrl + '" class="dp-search-result-item">' +
            '<div class="dp-search-result-icon">' + item.icon + '</div>' +
            '<div>' +
              '<div class="dp-search-result-title">' + item.name + '</div>' +
              '<div class="dp-search-result-meta">' + item.label.replace('-', ' & ') + '</div>' +
            '</div>' +
          '</a>';
        });
        if (matched.length > 6) {
          html += '<a href="' + blogUrl + 'search?q=' + encodeURIComponent(query) + '" class="dp-search-result-item" style="justify-content:center;color:var(--dp-primary);font-size:12px;font-weight:600;">Lihat semua ' + matched.length + ' hasil →</a>';
        }
        results.innerHTML = html;
      }
      results.classList.add('active');
    }, 150);
  };

  window.dpSearchFocus = function() {
    var input = document.getElementById('dpSearchInput');
    var results = document.getElementById('dpSearchResults');
    if (!input || !results) return;
    if (input.value.length >= 2) {
      results.classList.add('active');
    }
  };

  window.dpSearchBlur = function() {
    var results = document.getElementById('dpSearchResults');
    if (results) results.classList.remove('active');
  };

  // Handle Enter key on search
  (function() {
    var input = document.getElementById('dpSearchInput');
    if (!input) return;
    input.addEventListener('keydown', function(e) {
      if (e.key === 'Enter') {
        var q = input.value.trim();
        if (q) {
          window.location.href = blogUrl + 'search?q=' + encodeURIComponent(q);
        }
      }
    });
  })();

  /* ============================
     SOLVER CONTAINER WRAPPER
     ============================ */
  (function() {
    // Wrap all solver-container divs with our styled wrapper
    var solvers = document.querySelectorAll('.solver-container');
    solvers.forEach(function(solver) {
      if (!solver.parentElement.classList.contains('dp-solver-wrapper')) {
        var wrapper = document.createElement('div');
        wrapper.className = 'dp-solver-wrapper';
        var header = document.createElement('div');
        header.className = 'dp-solver-header';
        header.innerHTML = '<span class="dp-solver-header-icon"><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="2.5" stroke="white" stroke-width="1.5"/><path d="M9 1v2M9 15v2M1 9h2M15 9h2M3.2 3.2l1.4 1.4M13.4 13.4l1.4 1.4M3.2 14.8l1.4-1.4M13.4 4.6l1.4-1.4" stroke="white" stroke-width="1.5" stroke-linecap="round"/></svg></span>' +
          '<span class="dp-solver-header-title">Program Solver Interaktif</span>' +
          '<span class="dp-solver-header-badge">Live</span>';
        solver.parentNode.insertBefore(wrapper, solver);
        wrapper.appendChild(header);
        wrapper.appendChild(solver);
      }
    });
  })();

  /* ============================
     INTERSECTION OBSERVER ANIMATIONS
     ============================ */
  (function() {
    if (!window.IntersectionObserver) return;
    var observer = new IntersectionObserver(function(entries) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          entry.target.style.animationPlayState = 'running';
          observer.unobserve(entry.target);
        }
      });
    }, { threshold: 0.1, rootMargin: '0px 0px -50px 0px' });

    document.querySelectorAll('.dp-cat-card, .dp-post-card, .dp-info-card').forEach(function(el) {
      el.style.animationPlayState = 'paused';
      el.classList.add('dp-animate-in');
      observer.observe(el);
    });
  })();

  /* ============================
     KEYBOARD SHORTCUTS
     ============================ */
  document.addEventListener('keydown', function(e) {
    // Cmd/Ctrl + K to focus search
    if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
      e.preventDefault();
      var input = document.getElementById('dpSearchInput');
      if (input) {
        input.focus();
        input.select();
      }
    }
    // Escape to close sidebar / search
    if (e.key === 'Escape') {
      dpToggleSidebar(false);
      var results = document.getElementById('dpSearchResults');
      if (results) results.classList.remove('active');
    }
  });

  /* ============================
     SMOOTH ANCHOR SCROLLING
     ============================ */
  document.querySelectorAll('a[href^="#"]').forEach(function(anchor) {
    anchor.addEventListener('click', function(e) {
      var targetId = this.getAttribute('href').slice(1);
      var target = document.getElementById(targetId);
      if (target) {
        e.preventDefault();
        var topbarH = document.querySelector('.dp-topbar') ?
          document.querySelector('.dp-topbar').offsetHeight : 80;
        var top = target.getBoundingClientRect().top + window.scrollY - topbarH - 20;
        window.scrollTo({ top: top, behavior: 'smooth' });
      }
    });
  });

  /* ============================
     TOPBAR SHADOW ON SCROLL
     ============================ */
  (function() {
    var topbar = document.querySelector('.dp-topbar');
    if (!topbar) return;
    window.addEventListener('scroll', function() {
      if (window.scrollY > 10) {
        topbar.style.boxShadow = 'var(--dp-shadow)';
      } else {
        topbar.style.boxShadow = 'none';
      }
    }, { passive: true });
  })();

  console.log('%cDiskritProgram', 'color:#2563EB;font-size:16px;font-weight:bold;');
  console.log('%cKumpulan Program Matematika Diskrit', 'color:#64748B;font-size:12px;');

})();

